{
  "name": "LinguaListen AI",
  "description": "An AI-powered listening comprehension tool for English, Chinese, and Bahasa Melayu. Upload audio to instantly generate quizzes and get feedback.",
  "requestFramePermissions": [
    "microphone"
  ]
}

export type QuestionType = 'Multiple Choice' | 'Fill-in-the-Blank' | 'Short Answer' | 'True/False';

export interface Question {
  id: string;
  type: QuestionType;
  prompt: string;
  options?: string[];
  correct_answer: string;
  transcript_reference?: string;
}

export interface QuizData {
  quiz_title: string;
  language: string;
  transcript: string;
  questions: Question[];
}

export interface UserResponse {
  questionId: string;
  userAnswer: string;
  isCorrect: boolean;
  feedback?: string;
}

export interface QuizAttempt {
  id: string;
  date: string;
  quizTitle: string;
  score: number;
  totalQuestions: number;
  language: string;
}

export enum AppState {
  UPLOAD = 'UPLOAD',
  PROCESSING = 'PROCESSING',
  QUIZ = 'QUIZ',
  RESULTS = 'RESULTS',
  HISTORY = 'HISTORY'
}

import { GoogleGenAI, SchemaType } from "@google/genai";
import { QuizData, UserResponse, Question } from "../types";

const GEMINI_API_KEY = process.env.API_KEY || '';

const ai = new GoogleGenAI({ apiKey: GEMINI_API_KEY });

// Helper to convert file to Base64
export const fileToGenerativePart = async (file: File): Promise<{ inlineData: { data: string; mimeType: string } }> => {
  return new Promise((resolve, reject) => {
    const reader = new FileReader();
    reader.onloadend = () => {
      const base64String = (reader.result as string).split(',')[1];
      resolve({
        inlineData: {
          data: base64String,
          mimeType: file.type,
        },
      });
    };
    reader.onerror = reject;
    reader.readAsDataURL(file);
  });
};

export const generateQuizFromMedia = async (file: File): Promise<QuizData> => {
  const model = 'gemini-flash-latest'; // Using Flash for speed and multimodal capabilities

  const mediaPart = await fileToGenerativePart(file);

  const prompt = `
    You are an expert language teacher for English, Chinese (Mandarin), and Bahasa Melayu.
    Analyze the provided audio/video file.
    1. Detect the language used (English, Chinese, or Bahasa Melayu).
    2. Transcribe the audio content accurately.
    3. Generate a listening comprehension quiz with 5 to 8 questions.
    4. Questions must test comprehension, inference, and detail retention.
    5. Use a mix of "Multiple Choice", "True/False", "Fill-in-the-Blank", and "Short Answer".
    6. For "Multiple Choice", provide 3-4 options.
    7. Provide the "correct_answer" for grading.
    8. Provide a "transcript_reference" (excerpt) that supports the answer.

    Return the result in valid JSON format matching this schema:
    {
      "quiz_title": "A descriptive title",
      "language": "Detected Language",
      "transcript": "Full transcript text...",
      "questions": [
        {
          "id": "1",
          "type": "Multiple Choice",
          "prompt": "Question text...",
          "options": ["Option A", "Option B", "Option C"],
          "correct_answer": "Option B",
          "transcript_reference": "Relevant sentence from transcript"
        }
      ]
    }
  `;

  try {
    const response = await ai.models.generateContent({
      model: model,
      contents: {
        parts: [mediaPart, { text: prompt }]
      },
      config: {
        responseMimeType: 'application/json'
      }
    });

    const text = response.text;
    if (!text) throw new Error("No response from Gemini");

    return JSON.parse(text) as QuizData;
  } catch (error) {
    console.error("Error generating quiz:", error);
    throw error;
  }
};

export const generateFeedback = async (question: Question, userAnswer: string, language: string): Promise<string> => {
  // If exact match (case insensitive), no need for AI feedback usually, but we can still give positive reinforcement.
  // This function is primarily for incorrect or partial answers.

  const model = 'gemini-flash-latest';

  const prompt = `
    The user is taking a listening quiz in ${language}.
    Question: "${question.prompt}"
    Correct Answer: "${question.correct_answer}"
    User's Answer: "${userAnswer}"

    Compare the user's answer to the correct answer.
    Provide constructive feedback in one sentence.
    If the answer is wrong, explain why or hint at the correct usage.
    If the answer is correct but could be phrased better (especially for language learning), mention it.
    If it is completely correct, say "Correct!" or "Great job!".

    Examples:
    - "Good effort, but you missed the key verb 'purchased.' The correct phrase is 'purchased the tickets,' not 'bought the tickets.'"
    - "Jawapan anda hampir tepat, tetapi anda menggunakan 'telah' yang kurang sesuai. Perkataan yang lebih tepat ialah 'sedang'."
  `;

  try {
    const response = await ai.models.generateContent({
      model: model,
      contents: prompt,
    });
    return response.text || "Feedback unavailable.";
  } catch (error) {
    console.error("Error generating feedback:", error);
    return "Unable to generate detailed feedback at this time.";
  }
};

import React, { useState, useRef, DragEvent } from 'react';
import { Upload, FileAudio, X, FileVideo } from 'lucide-react';

interface FileUploadProps {
  onFileSelect: (file: File) => void;
}

const FileUpload: React.FC<FileUploadProps> = ({ onFileSelect }) => {
  const [isDragging, setIsDragging] = useState(false);
  const [selectedFile, setSelectedFile] = useState<File | null>(null);
  const fileInputRef = useRef<HTMLInputElement>(null);

  const handleDragEnter = (e: DragEvent<HTMLDivElement>) => {
    e.preventDefault();
    e.stopPropagation();
    setIsDragging(true);
  };

  const handleDragLeave = (e: DragEvent<HTMLDivElement>) => {
    e.preventDefault();
    e.stopPropagation();
    setIsDragging(false);
  };

  const handleDragOver = (e: DragEvent<HTMLDivElement>) => {
    e.preventDefault();
    e.stopPropagation();
    // This is crucial for allowing drop
  };

  const handleDrop = (e: DragEvent<HTMLDivElement>) => {
    e.preventDefault();
    e.stopPropagation();
    setIsDragging(false);

    if (e.dataTransfer.files && e.dataTransfer.files.length > 0) {
      const file = e.dataTransfer.files[0];
      validateAndSetFile(file);
    }
  };

  const handleFileInput = (e: React.ChangeEvent<HTMLInputElement>) => {
    if (e.target.files && e.target.files.length > 0) {
      validateAndSetFile(e.target.files[0]);
    }
  };

  const validateAndSetFile = (file: File) => {
    const validTypes = ['audio/mpeg', 'audio/wav', 'audio/mp3', 'video/mp4', 'video/quicktime', 'video/webm'];
    // Simple validation, can be expanded
    if (validTypes.some(type => file.type.includes(type.split('/')[1]) || file.type === type)) {
        setSelectedFile(file);
        onFileSelect(file);
    } else {
        alert("Please upload a valid audio or video file (MP3, WAV, MP4, MOV).");
    }
  };

  const removeFile = () => {
    setSelectedFile(null);
    if (fileInputRef.current) {
      fileInputRef.current.value = '';
    }
  };

  const formatFileSize = (bytes: number) => {
    if (bytes === 0) return '0 Bytes';
    const k = 1024;
    const sizes = ['Bytes', 'KB', 'MB', 'GB'];
    const i = Math.floor(Math.log(bytes) / Math.log(k));
    return parseFloat((bytes / Math.pow(k, i)).toFixed(2)) + ' ' + sizes[i];
  };

  return (
    <div className="w-full max-w-2xl mx-auto">
      {!selectedFile ? (
        <div
          onDragEnter={handleDragEnter}
          onDragLeave={handleDragLeave}
          onDragOver={handleDragOver}
          onDrop={handleDrop}
          onClick={() => fileInputRef.current?.click()}
          className={`
            relative border-2 border-dashed rounded-xl p-12 text-center cursor-pointer transition-all duration-300
            ${isDragging 
              ? 'border-indigo-500 bg-indigo-50 scale-[1.02]' 
              : 'border-slate-300 hover:border-indigo-400 hover:bg-slate-50'
            }
          `}
        >
          <input
            type="file"
            ref={fileInputRef}
            className="hidden"
            accept=".mp3,.wav,.mp4,.mov"
            onChange={handleFileInput}
          />
          <div className="flex flex-col items-center justify-center space-y-4">
            <div className={`p-4 rounded-full ${isDragging ? 'bg-indigo-100' : 'bg-slate-100'}`}>
              <Upload className={`w-8 h-8 ${isDragging ? 'text-indigo-600' : 'text-slate-500'}`} />
            </div>
            <div>
              <p className="text-lg font-medium text-slate-700">
                Drag & Drop your media file here
              </p>
              <p className="text-sm text-slate-500 mt-1">
                or click to browse (MP3, MP4, WAV, MOV)
              </p>
            </div>
            <div className="text-xs text-slate-400 mt-4">
              Max file size: 50MB
            </div>
          </div>
        </div>
      ) : (
        <div className="bg-white border border-slate-200 rounded-xl p-6 shadow-sm flex items-center justify-between">
          <div className="flex items-center space-x-4">
            <div className="p-3 bg-indigo-100 rounded-lg">
              {selectedFile.type.startsWith('video') ? (
                <FileVideo className="w-6 h-6 text-indigo-600" />
              ) : (
                <FileAudio className="w-6 h-6 text-indigo-600" />
              )}
            </div>
            <div>
              <p className="font-medium text-slate-800 truncate max-w-xs">
                {selectedFile.name}
              </p>
              <p className="text-sm text-slate-500">
                {formatFileSize(selectedFile.size)}
              </p>
            </div>
          </div>
          <button
            onClick={removeFile}
            className="p-2 hover:bg-red-50 text-slate-400 hover:text-red-500 rounded-full transition-colors"
          >
            <X className="w-5 h-5" />
          </button>
        </div>
      )}
    </div>
  );
};

export default FileUpload;

import React, { useState } from 'react';
import { QuizData, Question } from '../types';
import { CheckCircle2, Circle, Type } from 'lucide-react';

interface QuizDisplayProps {
  quizData: QuizData;
  onSubmit: (answers: Record<string, string>) => void;
}

const QuizDisplay: React.FC<QuizDisplayProps> = ({ quizData, onSubmit }) => {
  const [answers, setAnswers] = useState<Record<string, string>>({});
  const [showTranscript, setShowTranscript] = useState(false);

  const handleAnswerChange = (questionId: string, value: string) => {
    setAnswers((prev) => ({ ...prev, [questionId]: value }));
  };

  const handleSubmit = () => {
    // Basic validation to ensure all questions have some input could go here
    onSubmit(answers);
  };

  return (
    <div className="max-w-3xl mx-auto space-y-8 pb-12">
      <div className="bg-white rounded-2xl p-6 shadow-sm border border-slate-200">
        <div className="flex justify-between items-start mb-4">
          <div>
            <span className="inline-block px-3 py-1 bg-indigo-100 text-indigo-700 rounded-full text-xs font-semibold tracking-wide mb-2 uppercase">
              {quizData.language}
            </span>
            <h2 className="text-2xl font-bold text-slate-900">{quizData.quiz_title}</h2>
            <p className="text-slate-500 text-sm mt-1">{quizData.questions.length} Questions</p>
          </div>
          <button
            onClick={() => setShowTranscript(!showTranscript)}
            className="text-sm text-indigo-600 hover:text-indigo-800 font-medium underline underline-offset-2"
          >
            {showTranscript ? 'Hide Transcript' : 'Show Transcript'}
          </button>
        </div>

        {showTranscript && (
          <div className="mt-4 p-4 bg-slate-50 rounded-lg border border-slate-200 text-slate-700 text-sm leading-relaxed max-h-60 overflow-y-auto">
            {quizData.transcript}
          </div>
        )}
      </div>

      <div className="space-y-6">
        {quizData.questions.map((q, index) => (
          <div key={q.id} className="bg-white rounded-xl p-6 shadow-sm border border-slate-200 transition-all hover:shadow-md">
            <div className="flex items-start space-x-3 mb-4">
              <span className="flex-shrink-0 flex items-center justify-center w-8 h-8 rounded-full bg-slate-100 text-slate-600 font-bold text-sm">
                {index + 1}
              </span>
              <div className="flex-1">
                <h3 className="text-lg font-medium text-slate-900">{q.prompt}</h3>
                <span className="text-xs text-slate-400 font-medium uppercase tracking-wider">{q.type}</span>
              </div>
            </div>

            <div className="pl-11">
              {q.type === 'Multiple Choice' || q.type === 'True/False' ? (
                <div className="space-y-3">
                  {q.options?.map((option) => (
                    <label
                      key={option}
                      className={`
                        flex items-center p-3 rounded-lg border cursor-pointer transition-all
                        ${answers[q.id] === option 
                          ? 'border-indigo-500 bg-indigo-50 ring-1 ring-indigo-500' 
                          : 'border-slate-200 hover:bg-slate-50'
                        }
                      `}
                    >
                      <input
                        type="radio"
                        name={q.id}
                        value={option}
                        checked={answers[q.id] === option}
                        onChange={(e) => handleAnswerChange(q.id, e.target.value)}
                        className="sr-only"
                      />
                      <div className={`w-5 h-5 rounded-full border mr-3 flex items-center justify-center flex-shrink-0 ${answers[q.id] === option ? 'border-indigo-500 bg-indigo-500' : 'border-slate-300'}`}>
                        {answers[q.id] === option && <CheckCircle2 className="w-3.5 h-3.5 text-white" />}
                      </div>
                      <span className={`${answers[q.id] === option ? 'text-indigo-900 font-medium' : 'text-slate-700'}`}>
                        {option}
                      </span>
                    </label>
                  ))}
                </div>
              ) : (
                <div className="relative">
                  <div className="absolute inset-y-0 left-0 pl-3 flex items-center pointer-events-none">
                    <Type className="h-5 w-5 text-slate-400" />
                  </div>
                  <input
                    type="text"
                    placeholder="Type your answer here..."
                    value={answers[q.id] || ''}
                    onChange={(e) => handleAnswerChange(q.id, e.target.value)}
                    className="block w-full pl-10 pr-3 py-3 border border-slate-300 rounded-lg leading-5 bg-white placeholder-slate-400 focus:outline-none focus:placeholder-slate-300 focus:border-indigo-500 focus:ring-1 focus:ring-indigo-500 sm:text-sm transition-shadow"
                  />
                </div>
              )}
            </div>
          </div>
        ))}
      </div>

      <div className="flex justify-end pt-4">
        <button
          onClick={handleSubmit}
          disabled={Object.keys(answers).length === 0}
          className="bg-indigo-600 text-white px-8 py-3 rounded-lg font-semibold hover:bg-indigo-700 disabled:opacity-50 disabled:cursor-not-allowed transition-colors shadow-lg shadow-indigo-200"
        >
          Submit Quiz
        </button>
      </div>
    </div>
  );
};

export default QuizDisplay;

import React from 'react';
import { QuizData, UserResponse, Question } from '../types';
import { CheckCircle, XCircle, AlertCircle, RefreshCw, BarChart } from 'lucide-react';

interface ResultsViewProps {
  quizData: QuizData;
  userResponses: UserResponse[];
  onRetry: () => void;
  onHome: () => void;
  isLoadingFeedback: boolean;
}

const ResultsView: React.FC<ResultsViewProps> = ({ quizData, userResponses, onRetry, onHome, isLoadingFeedback }) => {
  const correctCount = userResponses.filter(r => r.isCorrect).length;
  const totalCount = quizData.questions.length;
  const percentage = Math.round((correctCount / totalCount) * 100);

  const getQuestionById = (id: string): Question | undefined => quizData.questions.find(q => q.id === id);

  return (
    <div className="max-w-3xl mx-auto pb-12">
      {/* Score Card */}
      <div className="bg-white rounded-2xl shadow-sm border border-slate-200 overflow-hidden mb-8">
        <div className="bg-slate-900 p-8 text-center text-white">
          <h2 className="text-3xl font-bold mb-2">Quiz Complete!</h2>
          <p className="text-slate-300 mb-6">Here is how you performed on "{quizData.quiz_title}"</p>

          <div className="inline-flex items-center justify-center w-32 h-32 rounded-full border-4 border-indigo-500 bg-slate-800 shadow-xl">
            <div className="text-center">
              <span className="block text-3xl font-bold text-white">{percentage}%</span>
              <span className="block text-xs text-slate-400 uppercase tracking-wide">Score</span>
            </div>
          </div>
          <div className="mt-4 text-slate-300 font-medium">
            {correctCount} out of {totalCount} correct
          </div>
        </div>
      </div>

      <div className="space-y-6">
        <h3 className="text-xl font-bold text-slate-800 px-2">Detailed Feedback</h3>

        {isLoadingFeedback && (
            <div className="p-4 bg-indigo-50 border border-indigo-100 rounded-lg flex items-center justify-center text-indigo-700 animate-pulse">
                <span>Generating linguistic feedback for your answers...</span>
            </div>
        )}

        {userResponses.map((response) => {
          const question = getQuestionById(response.questionId);
          if (!question) return null;

          return (
            <div 
              key={response.questionId} 
              className={`rounded-xl border p-6 bg-white shadow-sm ${response.isCorrect ? 'border-green-200' : 'border-red-200'}`}
            >
              <div className="flex items-start gap-4">
                <div className="flex-shrink-0 mt-1">
                  {response.isCorrect ? (
                    <CheckCircle className="w-6 h-6 text-green-500" />
                  ) : (
                    <XCircle className="w-6 h-6 text-red-500" />
                  )}
                </div>
                <div className="flex-1">
                  <h4 className="font-medium text-slate-900 text-lg mb-2">{question.prompt}</h4>

                  <div className="grid grid-cols-1 md:grid-cols-2 gap-4 text-sm mb-4">
                    <div className="p-3 rounded-lg bg-slate-50 border border-slate-100">
                      <span className="block text-xs text-slate-500 uppercase mb-1">Your Answer</span>
                      <span className={`font-medium ${response.isCorrect ? 'text-green-700' : 'text-red-700'}`}>
                        {response.userAnswer || '(No answer provided)'}
                      </span>
                    </div>
                    {!response.isCorrect && (
                      <div className="p-3 rounded-lg bg-slate-50 border border-slate-100">
                         <span className="block text-xs text-slate-500 uppercase mb-1">Correct Answer</span>
                         <span className="font-medium text-slate-900">{question.correct_answer}</span>
                      </div>
                    )}
                  </div>

                  {/* Transcript Reference */}
                  {question.transcript_reference && (
                     <div className="mt-2 text-xs text-slate-500 italic border-l-2 border-slate-200 pl-3">
                        Reference: "{question.transcript_reference}"
                     </div>
                  )}

                  {/* AI Feedback */}
                  {response.feedback && !response.isCorrect && (
                    <div className="mt-4 flex items-start gap-3 p-3 bg-indigo-50 rounded-lg border border-indigo-100">
                        <AlertCircle className="w-5 h-5 text-indigo-600 flex-shrink-0" />
                        <div className="text-sm text-indigo-800">
                            <span className="font-semibold block mb-1">AI Feedback:</span>
                            {response.feedback}
                        </div>
                    </div>
                  )}
                </div>
              </div>
            </div>
          );
        })}
      </div>

      <div className="mt-12 flex justify-center space-x-4">
        <button 
            onClick={onHome}
            className="flex items-center px-6 py-3 bg-white text-slate-700 border border-slate-300 rounded-lg hover:bg-slate-50 font-medium transition-colors"
        >
            <BarChart className="w-5 h-5 mr-2" />
            Dashboard
        </button>
        <button 
            onClick={onRetry}
            className="flex items-center px-6 py-3 bg-indigo-600 text-white rounded-lg hover:bg-indigo-700 font-medium transition-colors shadow-lg shadow-indigo-200"
        >
            <RefreshCw className="w-5 h-5 mr-2" />
            Try Another Quiz
        </button>
      </div>
    </div>
  );
};

export default ResultsView;

import React from 'react';
import { QuizAttempt } from '../types';
import { BarChart, Bar, XAxis, YAxis, Tooltip, ResponsiveContainer, Cell } from 'recharts';

interface HistoryChartProps {
  attempts: QuizAttempt[];
}

const HistoryChart: React.FC<HistoryChartProps> = ({ attempts }) => {
  if (attempts.length === 0) return null;

  // Process data for the chart - show last 5 attempts
  const data = attempts.slice(-5).map((attempt, index) => ({
    name: `Quiz ${index + 1}`,
    score: Math.round((attempt.score / attempt.totalQuestions) * 100),
    title: attempt.quizTitle,
    date: new Date(attempt.date).toLocaleDateString()
  }));

  return (
    <div className="bg-white p-6 rounded-xl border border-slate-200 shadow-sm">
      <h3 className="text-lg font-semibold text-slate-800 mb-6">Recent Performance</h3>
      <div className="h-64 w-full">
        <ResponsiveContainer width="100%" height="100%">
          <BarChart data={data} margin={{ top: 5, right: 20, bottom: 5, left: 0 }}>
            <XAxis 
                dataKey="name" 
                tick={{ fontSize: 12, fill: '#64748b' }} 
                axisLine={false} 
                tickLine={false} 
            />
            <YAxis 
                tick={{ fontSize: 12, fill: '#64748b' }} 
                axisLine={false} 
                tickLine={false} 
                domain={[0, 100]}
                unit="%"
            />
            <Tooltip 
                cursor={{ fill: '#f1f5f9' }}
                contentStyle={{ borderRadius: '8px', border: 'none', boxShadow: '0 4px 6px -1px rgb(0 0 0 / 0.1)' }}
            />
            <Bar dataKey="score" radius={[4, 4, 0, 0]}>
              {data.map((entry, index) => (
                <Cell key={`cell-${index}`} fill={entry.score >= 80 ? '#4f46e5' : entry.score >= 50 ? '#818cf8' : '#cbd5e1'} />
              ))}
            </Bar>
          </BarChart>
        </ResponsiveContainer>
      </div>
    </div>
  );
};

export default HistoryChart;

import React, { useState, useEffect } from 'react';
import FileUpload from './components/FileUpload';
import QuizDisplay from './components/QuizDisplay';
import ResultsView from './components/ResultsView';
import HistoryChart from './components/HistoryChart';
import { generateQuizFromMedia, generateFeedback } from './services/geminiService';
import { AppState, QuizData, UserResponse, QuizAttempt } from './types';
import { BookOpen, Loader2, Sparkles, BrainCircuit } from 'lucide-react';

const App: React.FC = () => {
  const [appState, setAppState] = useState<AppState>(AppState.UPLOAD);
  const [currentQuiz, setCurrentQuiz] = useState<QuizData | null>(null);
  const [userResponses, setUserResponses] = useState<UserResponse[]>([]);
  const [attempts, setAttempts] = useState<QuizAttempt[]>([]);
  const [isLoadingFeedback, setIsLoadingFeedback] = useState(false);
  const [loadingMessage, setLoadingMessage] = useState<string>('');

  // Load history from local storage on mount
  useEffect(() => {
    const saved = localStorage.getItem('linguaListen_history');
    if (saved) {
      try {
        setAttempts(JSON.parse(saved));
      } catch (e) {
        console.error("Failed to parse history");
      }
    }
  }, []);

  const handleFileSelect = async (file: File) => {
    setAppState(AppState.PROCESSING);
    setLoadingMessage('Uploading and analyzing media...');
    try {
      // Simulate "Listening" messages
      const msgs = ['Detecting language...', 'Transcribing audio...', 'Generating questions...'];
      let msgIdx = 0;
      const interval = setInterval(() => {
        if (msgIdx < msgs.length) {
          setLoadingMessage(msgs[msgIdx]);
          msgIdx++;
        }
      }, 2000);

      const quizData = await generateQuizFromMedia(file);
      clearInterval(interval);

      setCurrentQuiz(quizData);
      setAppState(AppState.QUIZ);
    } catch (error) {
      console.error(error);
      alert("Failed to process file. Please ensure your API key is set and try again.");
      setAppState(AppState.UPLOAD);
    }
  };

  const handleQuizSubmit = async (answers: Record<string, string>) => {
    if (!currentQuiz) return;

    setAppState(AppState.RESULTS);
    setIsLoadingFeedback(true);

    const responses: UserResponse[] = [];
    let correctCount = 0;

    // Initial grading pass
    for (const q of currentQuiz.questions) {
      const userAnswer = answers[q.id] || '';
      // Simple case-insensitive match for grading basic types
      const isCorrect = userAnswer.toLowerCase().trim() === q.correct_answer.toLowerCase().trim();

      if (isCorrect) correctCount++;

      responses.push({
        questionId: q.id,
        userAnswer,
        isCorrect,
      });
    }

    setUserResponses(responses);

    // Save attempt immediately
    const newAttempt: QuizAttempt = {
      id: Date.now().toString(),
      date: new Date().toISOString(),
      quizTitle: currentQuiz.quiz_title,
      score: correctCount,
      totalQuestions: currentQuiz.questions.length,
      language: currentQuiz.language
    };

    const updatedAttempts = [...attempts, newAttempt];
    setAttempts(updatedAttempts);
    localStorage.setItem('linguaListen_history', JSON.stringify(updatedAttempts));

    // Async Feedback Generation for incorrect/complex answers
    const feedbackPromises = responses.map(async (response) => {
       const question = currentQuiz.questions.find(q => q.id === response.questionId);
       if (!question) return response;

       // Only generate expensive AI feedback if wrong or it's a short answer (subjective)
       if (!response.isCorrect || question.type === 'Short Answer') {
          const feedback = await generateFeedback(question, response.userAnswer, currentQuiz.language);
          return { ...response, feedback };
       }
       return response;
    });

    try {
        const responsesWithFeedback = await Promise.all(feedbackPromises);
        setUserResponses(responsesWithFeedback);
    } catch (e) {
        console.error("Error fetching feedback", e);
    } finally {
        setIsLoadingFeedback(false);
    }
  };

  const handleRetry = () => {
    setAppState(AppState.UPLOAD);
    setCurrentQuiz(null);
    setUserResponses([]);
  };

  return (
    <div className="min-h-screen bg-slate-50 flex flex-col font-sans text-slate-900">
