import React, { useState, useEffect } from 'react';
import { QuizData, QuizAttempt, UserResponse } from '../types';
import { storageService } from '../services/storageService';
import { generateFeedback } from '../services/geminiService';
import QuizDisplay from './QuizDisplay';
import ResultsView from './ResultsView';
import HistoryChart from './HistoryChart';
import { PlayCircle, Award, User } from 'lucide-react';

const StudentDashboard: React.FC = () => {
  const [view, setView] = useState<'browse' | 'quiz' | 'results'>('browse');
  const [studentName, setStudentName] = useState('');
  const [quizzes, setQuizzes] = useState<QuizData[]>([]);
  const [activeQuiz, setActiveQuiz] = useState<QuizData | null>(null);
  const [userResponses, setUserResponses] = useState<UserResponse[]>([]);
  const [myAttempts, setMyAttempts] = useState<QuizAttempt[]>([]);
  const [isLoadingFeedback, setIsLoadingFeedback] = useState(false);

  useEffect(() => {
    // Check for saved name
    const savedName = localStorage.getItem('linguaListen_studentName');
    if (savedName) setStudentName(savedName);

    setQuizzes(storageService.getQuizzes());
  }, []);

  useEffect(() => {
    if (studentName) {
        setMyAttempts(storageService.getStudentAttempts(studentName));
    }
  }, [studentName]);

  const handleNameSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (studentName.trim()) {
        localStorage.setItem('linguaListen_studentName', studentName);
        setMyAttempts(storageService.getStudentAttempts(studentName));
    }
  };

  const startQuiz = (quiz: QuizData) => {
    setActiveQuiz(quiz);
    setView('quiz');
  };

  const handleQuizSubmit = async (answers: Record<string, string>) => {
    if (!activeQuiz) return;

    setView('results');
    setIsLoadingFeedback(true);

    const responses: UserResponse[] = [];
    let correctCount = 0;

    for (const q of activeQuiz.questions) {
      const userAnswer = answers[q.id] || '';
      const isCorrect = userAnswer.toLowerCase().trim() === q.correct_answer.toLowerCase().trim();
      if (isCorrect) correctCount++;
      responses.push({ questionId: q.id, userAnswer, isCorrect });
    }

    setUserResponses(responses);

    // Save attempt
    const newAttempt: QuizAttempt = {
      id: Date.now().toString(),
      date: new Date().toISOString(),
      quizId: activeQuiz.id,
      quizTitle: activeQuiz.quiz_title,
      studentName: studentName,
      score: correctCount,
      totalQuestions: activeQuiz.questions.length,
      language: activeQuiz.language
    };

    storageService.saveAttempt(newAttempt);
    setMyAttempts(prev => [newAttempt, ...prev]);

    // Async Feedback
    const feedbackPromises = responses.map(async (response) => {
       const question = activeQuiz.questions.find(q => q.id === response.questionId);
       if (!question) return response;

       if (!response.isCorrect || question.type === 'Short Answer') {
          const feedback = await generateFeedback(question, response.userAnswer, activeQuiz.language);
          return { ...response, feedback };
       }
       return response;
    });

    try {
        const responsesWithFeedback = await Promise.all(feedbackPromises);
        setUserResponses(responsesWithFeedback);
    } catch (e) {
        console.error("Error fetching feedback", e);
    } finally {
        setIsLoadingFeedback(false);
    }
  };

  if (!studentName) {
    return (
        <div className="min-h-[60vh] flex flex-col items-center justify-center max-w-md mx-auto px-4">
            <div className="bg-white p-8 rounded-2xl shadow-lg border border-slate-100 w-full text-center">
                <div className="w-16 h-16 bg-indigo-100 rounded-full flex items-center justify-center mx-auto mb-6">
                    <User className="w-8 h-8 text-indigo-600" />
                </div>
                <h2 className="text-2xl font-bold text-slate-900 mb-2">Student Profile</h2>
                <p className="text-slate-500 mb-6">Enter your name to track your progress and take quizzes.</p>
                <form onSubmit={handleNameSubmit} className="space-y-4">
                    <input 
                        type="text" 
                        value={studentName}
                        onChange={(e) => setStudentName(e.target.value)}
                        placeholder="Your Name (e.g. Ali, Sarah)"
                        className="w-full px-4 py-3 border border-slate-300 rounded-lg focus:ring-2 focus:ring-indigo-500 focus:border-indigo-500 outline-none transition-all"
                        required
                    />
                    <button type="submit" className="w-full py-3 bg-indigo-600 text-white rounded-lg font-semibold hover:bg-indigo-700 transition-colors">
                        Continue
                    </button>
                </form>
            </div>
        </div>
    );
  }

  if (view === 'quiz' && activeQuiz) {
    return (
        <div className="animate-fade-in">
            <button 
                onClick={() => setView('browse')}
                className="mb-6 text-slate-500 hover:text-indigo-600 font-medium flex items-center"
            >
                ← Back to Dashboard
            </button>
            <QuizDisplay quizData={activeQuiz} onSubmit={handleQuizSubmit} />
        </div>
    );
  }

  if (view === 'results' && activeQuiz) {
    return (
        <div className="animate-fade-in">
             <ResultsView 
              quizData={activeQuiz} 
              userResponses={userResponses} 
              onRetry={() => setView('browse')}
              onHome={() => setView('browse')}
              isLoadingFeedback={isLoadingFeedback}
            />
        </div>
    );
  }

  return (
    <div className="max-w-6xl mx-auto space-y-8 animate-fade-in">
        <div className="flex justify-between items-center bg-white p-6 rounded-xl border border-slate-200 shadow-sm">
            <div>
                <h1 className="text-2xl font-bold text-slate-900">Welcome back, {studentName}!</h1>
                <p className="text-slate-500">You have completed {myAttempts.length} quizzes so far.</p>
            </div>
            <button onClick={() => { localStorage.removeItem('linguaListen_studentName'); setStudentName(''); }} className="text-sm text-slate-400 hover:text-red-500">
                Sign Out
            </button>
        </div>

        <div className="grid grid-cols-1 lg:grid-cols-3 gap-8">
            <div className="lg:col-span-2 space-y-6">
                <h2 className="text-xl font-bold text-slate-800 flex items-center">
                    <PlayCircle className="w-5 h-5 mr-2 text-indigo-600" />
                    Available Quizzes
                </h2>
                <div className="grid gap-4 sm:grid-cols-2">
                    {quizzes.length === 0 ? (
                        <div className="col-span-full p-8 text-center bg-slate-50 rounded-xl border border-dashed border-slate-300 text-slate-500">
                            No quizzes available yet. Ask your teacher to publish one!
                        </div>
                    ) : (
                        quizzes.map(quiz => {
                            const lastAttempt = myAttempts.find(a => a.quizId === quiz.id);
                            return (
                                <div key={quiz.id} className="bg-white p-6 rounded-xl border border-slate-200 shadow-sm hover:shadow-md transition-all group">
                                    <div className="flex justify-between items-start mb-3">
                                        <span className="px-2 py-1 bg-indigo-50 text-indigo-700 text-xs font-bold rounded uppercase">{quiz.language}</span>
                                        {lastAttempt && (
                                            <span className="text-xs font-medium text-emerald-600 bg-emerald-50 px-2 py-1 rounded">
                                                Score: {Math.round((lastAttempt.score / lastAttempt.totalQuestions) * 100)}%
                                            </span>
                                        )}
                                    </div>
                                    <h3 className="font-bold text-slate-900 mb-2">{quiz.quiz_title}</h3>
                                    <p className="text-sm text-slate-500 mb-6">{quiz.questions.length} Questions</p>
                                    <button 
                                        onClick={() => startQuiz(quiz)}
                                        className="w-full py-2 bg-slate-50 text-slate-700 font-medium rounded-lg group-hover:bg-indigo-600 group-hover:text-white transition-colors"
                                    >
                                        {lastAttempt ? 'Retake Quiz' : 'Start Quiz'}
                                    </button>
                                </div>
                            );
                        })
                    )}
                </div>
            </div>

            <div className="space-y-6">
                <h2 className="text-xl font-bold text-slate-800 flex items-center">
                    <Award className="w-5 h-5 mr-2 text-amber-500" />
                    Your Progress
                </h2>
                <HistoryChart attempts={myAttempts} />

                <div className="bg-white rounded-xl border border-slate-200 shadow-sm overflow-hidden">
                    <div className="p-4 bg-slate-50 font-medium text-sm text-slate-700 border-b border-slate-200">Recent Activity</div>
                    <div className="divide-y divide-slate-100 max-h-64 overflow-y-auto">
                        {myAttempts.map(attempt => (
                            <div key={attempt.id} className="p-4 hover:bg-slate-50">
                                <p className="font-medium text-sm text-slate-900 truncate">{attempt.quizTitle}</p>
                                <div className="flex justify-between mt-1 text-xs text-slate-500">
                                    <span>{new Date(attempt.date).toLocaleDateString()}</span>
                                    <span className={attempt.score/attempt.totalQuestions >= 0.5 ? 'text-emerald-600' : 'text-red-500'}>
                                        {attempt.score}/{attempt.totalQuestions}
                                    </span>
                                </div>
                            </div>
                        ))}
                        {myAttempts.length === 0 && (
                            <div className="p-4 text-sm text-slate-400 text-center">No history yet.</div>
                        )}
                    </div>
                </div>
            </div>
        </div>
    </div>
  );
};

