                            <span>{generatedQuiz.questions.length} Questions</span>
                        </div>
                    </div>
                    <div className="flex flex-col gap-2 items-end">
                        <div className="bg-white px-4 py-2 rounded-lg border border-slate-200 text-center">
                            <span className="block text-xs text-slate-400 uppercase font-bold">Access Code</span>
                            <span className="block text-xl font-mono font-bold text-indigo-600">{generatedQuiz.accessCode}</span>
                        </div>
                        <span className="text-xs text-slate-500 font-medium bg-slate-200 px-2 py-1 rounded">
                             Replays: {generatedQuiz.replayLimit === 0 ? 'Unlimited' : generatedQuiz.replayLimit}
                        </span>
                    </div>
                 </div>

                 <div className="space-y-4">
                    {generatedQuiz.questions.map((q, idx) => (
                        <div key={idx} className="bg-white p-4 rounded-lg border border-slate-200">
                            <div className="flex gap-3">
                                <span className="flex-shrink-0 w-6 h-6 rounded-full bg-indigo-100 text-indigo-600 flex items-center justify-center text-xs font-bold">{idx + 1}</span>
                                <div>
                                    <p className="font-medium text-slate-800">{q.prompt}</p>
                                    <p className="text-xs text-slate-400 mt-1 uppercase">{q.type}</p>
                                    <p className="text-sm text-slate-600 mt-2"><span className="font-medium text-slate-500">Answer:</span> {q.correct_answer}</p>
                                </div>
                            </div>
                        </div>
                    ))}
                 </div>
              </div>
            </div>
          )}
        </div>
      )}

      {view === 'list' && (
        <div className="grid gap-6 md:grid-cols-2 lg:grid-cols-3">
            {quizzes.length === 0 ? (
                <div className="col-span-full py-20 text-center bg-white rounded-xl border border-dashed border-slate-300">
                    <LayoutList className="w-12 h-12 text-slate-300 mx-auto mb-4" />
                    <h3 className="text-lg font-medium text-slate-900">No quizzes yet</h3>
                    <p className="text-slate-500">Create your first quiz to get started.</p>
                </div>
            ) : (
                quizzes.map(quiz => (
                    <div key={quiz.id} className="bg-white p-6 rounded-xl border border-slate-200 shadow-sm hover:shadow-md transition-shadow relative">
                        <div className="flex justify-between items-start mb-4">
                            <div className="flex gap-2">
                                <span className="px-2 py-1 bg-indigo-100 text-indigo-700 text-xs font-bold rounded uppercase">{quiz.language}</span>
                                <span className="px-2 py-1 bg-slate-100 text-slate-600 text-xs font-bold rounded uppercase">{quiz.difficulty}</span>
                            </div>
                            <button onClick={() => deleteQuiz(quiz.id)} className="text-slate-400 hover:text-red-500">
                                <Trash2 className="w-5 h-5" />
                            </button>
                        </div>
                        <h3 className="text-lg font-bold text-slate-900 mb-2 truncate">{quiz.quiz_title}</h3>
                        <p className="text-sm text-slate-500 mb-4">{new Date(quiz.createdDate).toLocaleDateString()} • {quiz.questions.length} Questions</p>

                        <div className="mb-4 p-3 bg-slate-50 rounded-lg border border-slate-200 flex items-center justify-between group">
                            <div>
                                <span className="text-xs text-slate-400 uppercase font-bold block">Class Code</span>
                                <span className="text-lg font-mono font-bold text-slate-800 tracking-wider">{quiz.accessCode}</span>
                            </div>
                            <button 
                                onClick={() => copyToClipboard(quiz.accessCode, quiz.id)}
                                className="p-2 hover:bg-white rounded-md text-slate-400 hover:text-indigo-600 transition-colors"
                                title="Copy Code"
                            >
                                {copiedId === quiz.id ? <Check className="w-5 h-5 text-emerald-500" /> : <Copy className="w-5 h-5" />}
                            </button>
                        </div>

                        <div className="pt-4 border-t border-slate-100 flex items-center justify-between">
                            <div className="flex items-center text-sm text-slate-500">
                                <Users className="w-4 h-4 mr-2" />
                                {allAttempts.filter(a => a.quizId === quiz.id).length} Attempts
                            </div>
                            <div className="text-xs text-slate-400">
                                Replay Limit: {quiz.replayLimit === 0 || quiz.replayLimit === undefined ? '∞' : quiz.replayLimit}
                            </div>
                        </div>
                    </div>
                ))
            )}
        </div>
      )}

      {view === 'reports' && (
        <div className="bg-white rounded-xl shadow-sm border border-slate-200 overflow-hidden">
            <div className="p-6 border-b border-slate-100">
                <h3 className="text-lg font-bold text-slate-900">Recent Student Attempts</h3>
            </div>
            <div className="overflow-x-auto">
                <table className="w-full text-left text-sm text-slate-600">
                    <thead className="bg-slate-50 text-slate-900 font-semibold">
                        <tr>
                            <th className="p-4">Date</th>
                            <th className="p-4">Student</th>
                            <th className="p-4">Quiz Title</th>
                            <th className="p-4">Level</th>
                            <th className="p-4">Score</th>
                        </tr>
                    </thead>
                    <tbody className="divide-y divide-slate-100">
                        {allAttempts.length === 0 ? (
                            <tr>
                                <td colSpan={5} className="p-8 text-center text-slate-400">No student attempts recorded yet.</td>
                            </tr>
                        ) : (
                            allAttempts.map(attempt => (
                                <tr key={attempt.id} className="hover:bg-slate-50">
                                    <td className="p-4">{new Date(attempt.date).toLocaleDateString()}</td>
                                    <td className="p-4 font-medium text-slate-900">{attempt.studentName}</td>
                                    <td className="p-4">
                                        <div>{attempt.quizTitle}</div>
                                        <div className="text-xs text-slate-400 mt-0.5">{attempt.language}</div>
                                    </td>
                                    <td className="p-4">
                                        <span className="px-2 py-1 bg-slate-100 rounded text-xs text-slate-600 font-medium">{attempt.difficulty || 'N/A'}</span>
                                    </td>
                                    <td className="p-4">
                                        <span className={`inline-block px-2 py-1 rounded text-xs font-bold ${
                                            (attempt.score / attempt.totalQuestions) >= 0.8 ? 'bg-green-100 text-green-700' :
                                            (attempt.score / attempt.totalQuestions) >= 0.5 ? 'bg-yellow-100 text-yellow-700' : 'bg-red-100 text-red-700'
                                        }`}>
                                            {Math.round((attempt.score / attempt.totalQuestions) * 100)}%
                                        </span>
                                    </td>
                                </tr>
                            ))
                        )}
                    </tbody>
                </table>
            </div>
        </div>
      )}
    </div>
  );
};

export default TeacherDashboard;

import React, { useState, useRef } from 'react';
import { QuizData } from '../types';
import { CheckCircle2, Type, Play, Lock } from 'lucide-react';

interface QuizDisplayProps {
  quizData: QuizData;
  onSubmit: (answers: Record<string, string>) => void;
}

const QuizDisplay: React.FC<QuizDisplayProps> = ({ quizData, onSubmit }) => {
  const [answers, setAnswers] = useState<Record<string, string>>({});

  // Replay logic
  const limit = quizData.replayLimit ?? 0; // 0 means unlimited
  const [playsUsed, setPlaysUsed] = useState(0);
  const [isPlaying, setIsPlaying] = useState(false);
  const [showPlayer, setShowPlayer] = useState(false);
  const audioRef = useRef<HTMLAudioElement | HTMLVideoElement>(null);

  const handleAnswerChange = (questionId: string, value: string) => {
    setAnswers((prev) => ({ ...prev, [questionId]: value }));
  };

  const handleSubmit = () => {
    onSubmit(answers);
  };

  const handleMediaEnded = () => {
      setIsPlaying(false);
      // Increment plays used when media finishes
      if (limit > 0) {
          setPlaysUsed(prev => prev + 1);
          setShowPlayer(false); // Hide player to force user to click "Play" again (which checks limit)
      }
  };

  const startPlayback = () => {
      if (limit > 0 && playsUsed >= limit) return;
      setShowPlayer(true);
      setTimeout(() => {
          if(audioRef.current) {
              audioRef.current.play().then(() => {
                  setIsPlaying(true);
              }).catch(e => console.error("Playback failed", e));
          }
      }, 100);
  };

  const isUnlimited = limit === 0;
  const attemptsLeft = limit - playsUsed;
  const canPlay = isUnlimited || attemptsLeft > 0;

  return (
    <div className="max-w-3xl mx-auto space-y-8 pb-12">
      <div className="bg-white rounded-2xl p-6 shadow-sm border border-slate-200">
        <div className="mb-6">
          <span className="inline-block px-3 py-1 bg-indigo-100 text-indigo-700 rounded-full text-xs font-semibold tracking-wide mb-2 uppercase">
            {quizData.language}
          </span>
          <h2 className="text-2xl font-bold text-slate-900">{quizData.quiz_title}</h2>
          <p className="text-slate-500 text-sm mt-1">{quizData.questions.length} Questions</p>
        </div>

        {/* Media Player Section */}
        <div className="bg-slate-900 rounded-xl overflow-hidden relative min-h-[120px] flex items-center justify-center">
            {showPlayer ? (
                <div className="w-full p-4">
                     {quizData.mediaType?.startsWith('video') ? (
                        <video 
                            ref={audioRef as React.RefObject<HTMLVideoElement>}
                            src={quizData.mediaData}
                            controls
                            className="w-full rounded"
                            onEnded={handleMediaEnded}
                            controlsList={limit > 0 ? "nodownload" : ""}
                        />
                     ) : (
                        <audio 
                            ref={audioRef as React.RefObject<HTMLAudioElement>}
                            src={quizData.mediaData}
                            controls
                            className="w-full"
                            onEnded={handleMediaEnded}
                            controlsList={limit > 0 ? "nodownload" : ""}
                        />
                     )}
                     {!isUnlimited && (
                         <div className="text-center mt-2 text-xs text-slate-400">
                             Playing... (Do not reload page)
                         </div>
                     )}
                </div>
            ) : (
                <div className="text-center p-6 w-full">
                    {canPlay ? (
                        <div className="space-y-3">
                            <button 
                                onClick={startPlayback}
                                className="inline-flex items-center justify-center w-16 h-16 rounded-full bg-indigo-600 text-white hover:bg-indigo-500 hover:scale-105 transition-all shadow-lg shadow-indigo-900/50"
                            >
                                <Play className="w-8 h-8 ml-1" />
                            </button>
                            <div>
                                <h3 className="text-white font-medium">Click to Start Audio</h3>
                                {!isUnlimited && (
                                    <p className="text-indigo-200 text-sm mt-1">
                                        {attemptsLeft} {attemptsLeft === 1 ? 'play' : 'plays'} remaining
                                    </p>
                                )}
                            </div>
                        </div>
                    ) : (
                        <div className="space-y-3 opacity-75">
                             <div className="inline-flex items-center justify-center w-16 h-16 rounded-full bg-slate-700 text-slate-400">
                                <Lock className="w-8 h-8" />
                            </div>
                            <div>
                                <h3 className="text-slate-300 font-medium">Playback Limit Reached</h3>
                                <p className="text-slate-500 text-sm mt-1">You can no longer listen to the audio.</p>
                            </div>
                        </div>
                    )}
                </div>
            )}
        </div>
      </div>

      <div className="space-y-6">
        {quizData.questions.map((q, index) => (
          <div key={q.id} className="bg-white rounded-xl p-6 shadow-sm border border-slate-200 transition-all hover:shadow-md">
            <div className="flex items-start space-x-3 mb-4">
              <span className="flex-shrink-0 flex items-center justify-center w-8 h-8 rounded-full bg-slate-100 text-slate-600 font-bold text-sm">
                {index + 1}
              </span>
              <div className="flex-1">
                <h3 className="text-lg font-medium text-slate-900">{q.prompt}</h3>
                <span className="text-xs text-slate-400 font-medium uppercase tracking-wider">{q.type}</span>
              </div>
            </div>

            <div className="pl-11">
              {q.type === 'Multiple Choice' || q.type === 'True/False' ? (
                <div className="space-y-3">
                  {q.options?.map((option) => (
                    <label
                      key={option}
                      className={`
                        flex items-center p-3 rounded-lg border cursor-pointer transition-all
                        ${answers[q.id] === option 
                          ? 'border-indigo-500 bg-indigo-50 ring-1 ring-indigo-500' 
                          : 'border-slate-200 hover:bg-slate-50'
                        }
                      `}
                    >
                      <input
                        type="radio"
                        name={q.id}
                        value={option}
                        checked={answers[q.id] === option}
                        onChange={(e) => handleAnswerChange(q.id, e.target.value)}
                        className="sr-only"
                      />
                      <div className={`w-5 h-5 rounded-full border mr-3 flex items-center justify-center flex-shrink-0 ${answers[q.id] === option ? 'border-indigo-500 bg-indigo-500' : 'border-slate-300'}`}>
                        {answers[q.id] === option && <CheckCircle2 className="w-3.5 h-3.5 text-white" />}
                      </div>
                      <span className={`${answers[q.id] === option ? 'text-indigo-900 font-medium' : 'text-slate-700'}`}>
                        {option}
                      </span>
                    </label>
                  ))}
                </div>
              ) : (
                <div className="relative">
                  <div className="absolute inset-y-0 left-0 pl-3 flex items-center pointer-events-none">
                    <Type className="h-5 w-5 text-slate-400" />
                  </div>
                  <input
                    type="text"
                    placeholder="Type your answer here..."
                    value={answers[q.id] || ''}
                    onChange={(e) => handleAnswerChange(q.id, e.target.value)}
                    className="block w-full pl-10 pr-3 py-3 border border-slate-300 rounded-lg leading-5 bg-white placeholder-slate-400 focus:outline-none focus:placeholder-slate-300 focus:border-indigo-500 focus:ring-1 focus:ring-indigo-500 sm:text-sm transition-shadow"
                  />
                </div>
              )}
            </div>
          </div>
        ))}
      </div>

      <div className="flex justify-end pt-4">
        <button
          onClick={handleSubmit}
          disabled={Object.keys(answers).length === 0}
          className="bg-indigo-600 text-white px-8 py-3 rounded-lg font-semibold hover:bg-indigo-700 disabled:opacity-50 disabled:cursor-not-allowed transition-colors shadow-lg shadow-indigo-200"
        >
          Submit Quiz
        </button>
      </div>
    </div>
  );
};

export default QuizDisplay;

import React, { useState, useEffect } from 'react';
import { QuizData, QuizAttempt, UserResponse } from '../types';
import { storageService } from '../services/storageService';
import { generateFeedback } from '../services/geminiService';
import QuizDisplay from './QuizDisplay';
import ResultsView from './ResultsView';
import HistoryChart from './HistoryChart';
import { PlayCircle, Award, User, Search, KeyRound } from 'lucide-react';

const StudentDashboard: React.FC = () => {
  const [view, setView] = useState<'join' | 'quiz' | 'results'>('join');
  const [studentName, setStudentName] = useState(''); // Confirmed name (logged in)
  const [nameInput, setNameInput] = useState(''); // Form input state
  const [joinCode, setJoinCode] = useState('');
  const [activeQuiz, setActiveQuiz] = useState<QuizData | null>(null);
  const [userResponses, setUserResponses] = useState<UserResponse[]>([]);
  const [myAttempts, setMyAttempts] = useState<QuizAttempt[]>([]);
  const [isLoadingFeedback, setIsLoadingFeedback] = useState(false);
  const [joinError, setJoinError] = useState('');

  useEffect(() => {
    // Check for saved name
    const savedName = localStorage.getItem('linguaListen_studentName');
    if (savedName) {
        setStudentName(savedName);
        setNameInput(savedName);
    }
  }, []);

  useEffect(() => {
    if (studentName) {
        setMyAttempts(storageService.getStudentAttempts(studentName));
    }
  }, [studentName]);

  const handleNameSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (nameInput.trim()) {
        const cleanName = nameInput.trim();
        localStorage.setItem('linguaListen_studentName', cleanName);
        setStudentName(cleanName);
        setMyAttempts(storageService.getStudentAttempts(cleanName));
    }
  };

  const handleSignOut = () => {
    localStorage.removeItem('linguaListen_studentName'); 
    setStudentName('');
    setNameInput('');
  };

  const handleJoinQuiz = (e: React.FormEvent) => {
    e.preventDefault();
    setJoinError('');

    if (joinCode.length !== 6) {
        setJoinError('Please enter a valid 6-digit code.');
        return;
    }

    const allQuizzes = storageService.getQuizzes();
    const quiz = allQuizzes.find(q => q.accessCode === joinCode);

    if (quiz) {
        setActiveQuiz(quiz);
        setView('quiz');
        setJoinCode('');
    } else {
        setJoinError('Quiz not found. Please check the code.');
    }
  };

  const handleQuizSubmit = async (answers: Record<string, string>) => {
    if (!activeQuiz) return;

    setView('results');
    setIsLoadingFeedback(true);

    const responses: UserResponse[] = [];
    let correctCount = 0;

    for (const q of activeQuiz.questions) {
      const userAnswer = answers[q.id] || '';
      const isCorrect = userAnswer.toLowerCase().trim() === q.correct_answer.toLowerCase().trim();
      if (isCorrect) correctCount++;
      responses.push({ questionId: q.id, userAnswer, isCorrect });
    }

    setUserResponses(responses);

    // Save attempt
    const newAttempt: QuizAttempt = {
      id: Date.now().toString(),
      date: new Date().toISOString(),
      quizId: activeQuiz.id,
      quizTitle: activeQuiz.quiz_title,
      studentName: studentName,
      score: correctCount,
      totalQuestions: activeQuiz.questions.length,
      language: activeQuiz.language,
      difficulty: activeQuiz.difficulty
    };

    storageService.saveAttempt(newAttempt);
    setMyAttempts(prev => [newAttempt, ...prev]);

    // Async Feedback
    const feedbackPromises = responses.map(async (response) => {
       const question = activeQuiz.questions.find(q => q.id === response.questionId);
       if (!question) return response;

       if (!response.isCorrect || question.type === 'Short Answer') {
          const feedback = await generateFeedback(question, response.userAnswer, activeQuiz.language);
          return { ...response, feedback };
       }
       return response;
    });

    try {
        const responsesWithFeedback = await Promise.all(feedbackPromises);
        setUserResponses(responsesWithFeedback);
    } catch (e) {
        console.error("Error fetching feedback", e);
    } finally {
        setIsLoadingFeedback(false);
    }
  };

  if (!studentName) {
    return (
        <div className="min-h-[60vh] flex flex-col items-center justify-center max-w-md mx-auto px-4">
            <div className="bg-white p-8 rounded-2xl shadow-lg border border-slate-100 w-full text-center">
                <div className="w-16 h-16 bg-indigo-100 rounded-full flex items-center justify-center mx-auto mb-6">
                    <User className="w-8 h-8 text-indigo-600" />
                </div>
                <h2 className="text-2xl font-bold text-slate-900 mb-2">Student Profile</h2>
                <p className="text-slate-500 mb-6">Enter your name to track your progress and take quizzes.</p>
                <form onSubmit={handleNameSubmit} className="space-y-4">
                    <input 
                        type="text" 
                        value={nameInput}
                        onChange={(e) => setNameInput(e.target.value)}
                        placeholder="Your Name (e.g. Ali, Sarah)"
                        className="w-full px-4 py-3 border border-slate-300 rounded-lg focus:ring-2 focus:ring-indigo-500 focus:border-indigo-500 outline-none transition-all"
                        required
                    />
                    <button type="submit" className="w-full py-3 bg-indigo-600 text-white rounded-lg font-semibold hover:bg-indigo-700 transition-colors">
                        Continue
                    </button>
                </form>
            </div>
        </div>
    );
  }

  if (view === 'quiz' && activeQuiz) {
    return (
        <div className="animate-fade-in">
            <button 
                onClick={() => setView('join')}
                className="mb-6 text-slate-500 hover:text-indigo-600 font-medium flex items-center"
            >
                ← Back to Dashboard
            </button>
            <QuizDisplay 
                quizData={activeQuiz} 
                studentName={studentName}
                onSubmit={handleQuizSubmit} 
            />
        </div>
    );
  }

  if (view === 'results' && activeQuiz) {
    return (
        <div className="animate-fade-in">
             <ResultsView 
              quizData={activeQuiz} 
              userResponses={userResponses} 
              onRetry={() => setView('join')}
              onHome={() => setView('join')}
              isLoadingFeedback={isLoadingFeedback}
            />
        </div>
    );
  }

  return (
    <div className="max-w-6xl mx-auto space-y-8 animate-fade-in">
        <div className="flex justify-between items-center bg-white p-6 rounded-xl border border-slate-200 shadow-sm">
            <div>
                <h1 className="text-2xl font-bold text-slate-900">Welcome back, {studentName}!</h1>
                <p className="text-slate-500">You have completed {myAttempts.length} quizzes so far.</p>
            </div>
            <button onClick={handleSignOut} className="text-sm text-slate-400 hover:text-red-500">
                Sign Out
            </button>
        </div>

        <div className="grid grid-cols-1 lg:grid-cols-3 gap-8">
            <div className="lg:col-span-2">
                <div className="bg-indigo-600 rounded-2xl p-8 text-white shadow-xl shadow-indigo-200">
                    <div className="flex items-center space-x-3 mb-4">
                        <KeyRound className="w-8 h-8 text-indigo-200" />
                        <h2 className="text-2xl font-bold">Join a Quiz</h2>
                    </div>
                    <p className="text-indigo-100 mb-6">Enter the 6-digit access code provided by your teacher to start a new listening comprehension quiz.</p>

                    <form onSubmit={handleJoinQuiz} className="max-w-md">
                        <div className="relative">
                            <input 
                                type="text" 
                                value={joinCode}
                                onChange={(e) => setJoinCode(e.target.value.replace(/\D/g, '').slice(0, 6))}
                                placeholder="Enter 6-digit code"
                                className="w-full pl-4 pr-32 py-4 rounded-xl text-slate-900 placeholder-slate-400 font-bold text-lg tracking-widest focus:outline-none focus:ring-4 focus:ring-indigo-400"
                            />
                            <button 
                                type="submit"
                                className="absolute right-2 top-2 bottom-2 px-6 bg-indigo-800 hover:bg-indigo-900 text-white font-bold rounded-lg transition-colors"
                            >
                                JOIN
                            </button>
                        </div>
                        {joinError && (
                            <div className="mt-3 text-red-200 text-sm font-medium bg-red-500/20 py-1 px-3 rounded inline-block">
                                {joinError}
                            </div>
                        )}
                    </form>
                </div>
            </div>

            <div className="space-y-6">
                <h2 className="text-xl font-bold text-slate-800 flex items-center">
                    <Award className="w-5 h-5 mr-2 text-amber-500" />
                    Your Progress
                </h2>
                <HistoryChart attempts={myAttempts} />

                <div className="bg-white rounded-xl border border-slate-200 shadow-sm overflow-hidden">
                    <div className="p-4 bg-slate-50 font-medium text-sm text-slate-700 border-b border-slate-200">Recent Activity</div>
                    <div className="divide-y divide-slate-100 max-h-64 overflow-y-auto">
                        {myAttempts.map(attempt => (
                            <div key={attempt.id} className="p-4 hover:bg-slate-50">
                                <p className="font-medium text-sm text-slate-900 truncate">{attempt.quizTitle}</p>
                                <div className="flex justify-between mt-1 text-xs text-slate-500">
                                    <span>{new Date(attempt.date).toLocaleDateString()}</span>
                                    <span className={attempt.score/attempt.totalQuestions >= 0.5 ? 'text-emerald-600' : 'text-red-500'}>
                                        {attempt.score}/{attempt.totalQuestions}
                                    </span>
                                </div>
                            </div>
                        ))}
                        {myAttempts.length === 0 && (
                            <div className="p-4 text-sm text-slate-400 text-center">No history yet.</div>
                        )}
                    </div>
                </div>
            </div>
        </div>
    </div>
  );
};

