import { storageService } from '../services/storageService';
import { generateQuizFromMedia } from '../services/geminiService';
import { Loader2, Plus, LayoutList, Trash2, Users, Copy, Check, Info, Timer, HelpCircle, Calendar, Clock } from 'lucide-react';

const TeacherDashboard: React.FC = () => {
  const [view, setView] = useState<'create' | 'list' | 'reports'>('list');
  const [quizzes, setQuizzes] = useState<QuizData[]>([]);
  const [loading, setLoading] = useState(false);
  const [loadingMessage, setLoadingMessage] = useState('');
  const [generatedQuiz, setGeneratedQuiz] = useState<QuizData | null>(null);
  const [allAttempts, setAllAttempts] = useState<QuizAttempt[]>([]);
  const [difficulty, setDifficulty] = useState<Difficulty>('Intermediate');
  const [replayLimit, setReplayLimit] = useState<number>(2); // Default 2 replays
  const [questionCount, setQuestionCount] = useState<number>(5);
  const [timeLimit, setTimeLimit] = useState<number>(0); // 0 = unlimited
  const [copiedId, setCopiedId] = useState<string | null>(null);

  // Scheduling state
  const [publishMode, setPublishMode] = useState<'now' | 'later'>('now');
  const [scheduleDate, setScheduleDate] = useState('');

  useEffect(() => {
    loadData();
  }, []);

  const loadData = () => {
    setQuizzes(storageService.getQuizzes());
    setAllAttempts(storageService.getAttempts());
  };

  const handleFileSelect = async (file: File) => {
    setLoading(true);
    setLoadingMessage(`Processing media for ${difficulty} level...`);

    // Simulate steps for better UX
    const steps = ['Uploading media...', 'Transcribing audio...', 'Analyzing language...', 'Creating questions...'];
    let stepIdx = 0;
    const interval = setInterval(() => {
        if(stepIdx < steps.length) {
            setLoadingMessage(steps[stepIdx]);
            stepIdx++;
        }
    }, 2000);

    try {
      const quiz = await generateQuizFromMedia(file, difficulty, replayLimit, questionCount, timeLimit);
      clearInterval(interval);
      setGeneratedQuiz(quiz);
      // Reset scheduling options
      setPublishMode('now');
      setScheduleDate('');
    } catch (error) {
      clearInterval(interval);
      console.error(error);
      alert('Error generating quiz. Please try again. Note: Large files may exceed browser storage limits.');
    } finally {
      setLoading(false);
    }
  };

  const saveQuiz = () => {
    if (generatedQuiz) {
      if (publishMode === 'later' && !scheduleDate) {
          alert('Please select a date and time to publish the quiz.');
          return;
      }

      try {
          const finalQuiz = {
              ...generatedQuiz,
              publishedAt: publishMode === 'now' 
                  ? new Date().toISOString() 
                  : new Date(scheduleDate).toISOString()
          };

          storageService.saveQuiz(finalQuiz);
          loadData();
          setGeneratedQuiz(null);
          setView('list');
          alert(publishMode === 'now' ? 'Quiz published successfully!' : 'Quiz scheduled successfully!');
      } catch (e) {
          alert('Failed to save quiz. The file might be too large for browser storage.');
      }
    }
  };

  const deleteQuiz = (id: string) => {
    if (confirm('Are you sure you want to delete this quiz?')) {
      storageService.deleteQuiz(id);
      loadData();
    }
  };

  const copyToClipboard = (code: string, id: string) => {
    navigator.clipboard.writeText(code);
    setCopiedId(id);
    setTimeout(() => setCopiedId(null), 2000);
  };

  const isScheduled = (quiz: QuizData) => {
      return new Date(quiz.publishedAt) > new Date();
  };

  return (
    <div className="max-w-6xl mx-auto space-y-8 animate-fade-in">
      <div className="flex justify-between items-center">
        <div>
          <h1 className="text-3xl font-bold text-slate-900">Teacher Dashboard</h1>
          <p className="text-slate-500 mt-1">Manage content and view student progress</p>
        </div>
        <div className="flex space-x-3">
          <button
            onClick={() => setView('list')}
            className={`px-4 py-2 rounded-lg font-medium transition-colors ${view === 'list' ? 'bg-indigo-100 text-indigo-700' : 'text-slate-600 hover:bg-slate-100'}`}
          >
            My Quizzes
          </button>
          <button
            onClick={() => setView('reports')}
            className={`px-4 py-2 rounded-lg font-medium transition-colors ${view === 'reports' ? 'bg-indigo-100 text-indigo-700' : 'text-slate-600 hover:bg-slate-100'}`}
          >
            Student Reports
          </button>
          <button
            onClick={() => { setView('create'); setGeneratedQuiz(null); }}
            className="flex items-center px-4 py-2 bg-indigo-600 text-white rounded-lg hover:bg-indigo-700 transition-colors shadow-sm"
          >
            <Plus className="w-5 h-5 mr-2" />
            Create Quiz
          </button>
        </div>
      </div>

      {view === 'create' && (
        <div className="bg-white rounded-xl p-8 border border-slate-200 shadow-sm">
          {!generatedQuiz && !loading && (
            <div className="max-w-xl mx-auto space-y-8">
              <div className="text-center">
                <h2 className="text-2xl font-bold text-slate-800">Create New Quiz</h2>
                <p className="text-slate-500 mt-2">Configure and upload media to generate questions.</p>
              </div>

              <div className="space-y-6 bg-slate-50 p-6 rounded-xl border border-slate-200">

                {/* Difficulty Selector */}
                <div>
                    <label className="block text-sm font-medium text-slate-700 mb-2">Select Difficulty Level</label>
                    <div className="grid grid-cols-3 gap-4">
                        {['Beginner', 'Intermediate', 'Advanced'].map((level) => (
                            <button
                                key={level}
                                onClick={() => setDifficulty(level as Difficulty)}
                                className={`py-3 px-4 rounded-lg text-sm font-medium border-2 transition-all ${
                                    difficulty === level 
                                    ? 'border-indigo-600 bg-indigo-50 text-indigo-700' 
                                    : 'border-slate-200 bg-white text-slate-600 hover:border-indigo-300'
                                }`}
                            >
                                {level}
                            </button>
                        ))}
                    </div>
                </div>

                <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                    {/* Question Count */}
                    <div>
                        <div className="flex items-center space-x-2 mb-2">
                             <HelpCircle className="w-4 h-4 text-slate-400" />
                             <label className="block text-sm font-medium text-slate-700">Questions to Generate</label>
                        </div>
                        <select 
                            value={questionCount}
                            onChange={(e) => setQuestionCount(Number(e.target.value))}
                            className="w-full p-3 bg-white border border-slate-300 rounded-lg focus:ring-2 focus:ring-indigo-500 focus:border-indigo-500 transition-shadow"
                        >
                            {[3, 5, 8, 10, 12].map(count => (
                                <option key={count} value={count}>{count} Questions</option>
                            ))}
                        </select>
                    </div>

                    {/* Time Limit */}
                    <div>
                        <div className="flex items-center space-x-2 mb-2">
                             <Timer className="w-4 h-4 text-slate-400" />
                             <label className="block text-sm font-medium text-slate-700">Time Limit</label>
                        </div>
                        <select 
                            value={timeLimit}
                            onChange={(e) => setTimeLimit(Number(e.target.value))}
                            className="w-full p-3 bg-white border border-slate-300 rounded-lg focus:ring-2 focus:ring-indigo-500 focus:border-indigo-500 transition-shadow"
                        >
                            <option value={0}>No Time Limit</option>
                            <option value={5}>5 Minutes</option>
                            <option value={10}>10 Minutes</option>
                            <option value={15}>15 Minutes</option>
                            <option value={30}>30 Minutes</option>
                            <option value={60}>60 Minutes</option>
                        </select>
                    </div>
                </div>

                {/* Replay Limit Selector */}
                <div>
                     <div className="flex items-center justify-between mb-2">
                        <label className="block text-sm font-medium text-slate-700">Audio Replay Limit</label>
                        <div className="group relative flex items-center">
                            <Info className="w-4 h-4 text-slate-400 cursor-help" />
                            <div className="absolute bottom-full right-0 mb-2 w-48 p-2 bg-slate-800 text-white text-xs rounded shadow-lg hidden group-hover:block">
                                Number of times a student can play the audio clip.
                            </div>
                        </div>
                     </div>
                     <div className="grid grid-cols-5 gap-3">
                        {[1, 2, 3, 5, 0].map((limit) => (
                            <button
                                key={limit}
                                onClick={() => setReplayLimit(limit)}
                                className={`py-2 px-3 rounded-lg text-sm font-medium border-2 transition-all ${
                                    replayLimit === limit 
                                    ? 'border-indigo-600 bg-indigo-50 text-indigo-700' 
                                    : 'border-slate-200 bg-white text-slate-600 hover:border-indigo-300'
                                }`}
                            >
                                {limit === 0 ? 'Unlimited' : limit}
                            </button>
                        ))}
                     </div>
                </div>

                <div className="text-xs text-slate-500 bg-blue-50 p-3 rounded text-center border border-blue-100">
                   Note: File size affects storage. Please use short clips (under 5MB) for best performance.
                </div>
              </div>

              <FileUpload onFileSelect={handleFileSelect} />
            </div>
          )}

          {loading && (
            <div className="flex flex-col items-center justify-center py-20 space-y-6">
              <Loader2 className="w-12 h-12 text-indigo-600 animate-spin" />
              <p className="text-lg font-medium text-slate-700">{loadingMessage}</p>
            </div>
          )}

          {generatedQuiz && (
            <div className="space-y-6">
              <div className="bg-emerald-50 border border-emerald-100 rounded-lg p-6 flex flex-col md:flex-row items-center justify-between gap-4">
                <div>
                  <h3 className="font-bold text-emerald-800 text-lg">Quiz Generated Successfully!</h3>
                  <p className="text-emerald-600 text-sm">Review the questions below and set publication options.</p>
                </div>

                <div className="flex flex-col md:flex-row gap-4 items-center">
                    {/* Publishing Options */}
                    <div className="flex bg-white rounded-lg p-1 border border-emerald-200">
                        <button
                            onClick={() => setPublishMode('now')}
                            className={`px-4 py-2 rounded text-sm font-medium transition-colors ${
                                publishMode === 'now' ? 'bg-emerald-100 text-emerald-800' : 'text-slate-500 hover:bg-slate-50'
                            }`}
                        >
                            Publish Now
                        </button>
                        <button
                             onClick={() => setPublishMode('later')}
                             className={`px-4 py-2 rounded text-sm font-medium transition-colors ${
                                publishMode === 'later' ? 'bg-emerald-100 text-emerald-800' : 'text-slate-500 hover:bg-slate-50'
                            }`}
                        >
                            Schedule
                        </button>
                    </div>

                    {publishMode === 'later' && (
                        <input 
                            type="datetime-local"
                            value={scheduleDate}
                            onChange={(e) => setScheduleDate(e.target.value)}
                            min={new Date().toISOString().slice(0, 16)}
                            className="px-3 py-2 border border-emerald-300 rounded-lg text-sm text-slate-700 focus:outline-none focus:ring-2 focus:ring-emerald-500"
                        />
                    )}

                    <button
                    onClick={saveQuiz}
                    className="px-6 py-2 bg-emerald-600 text-white rounded-lg hover:bg-emerald-700 font-medium shadow-sm transition-colors whitespace-nowrap"
                    >
                        {publishMode === 'now' ? 'Publish Quiz' : 'Save Schedule'}
                    </button>
                </div>
              </div>

              <div className="bg-slate-50 rounded-xl p-6 border border-slate-200">
                 <div className="flex justify-between items-start mb-6">
                    <div>
                        <h2 className="text-xl font-bold text-slate-900 mb-1">{generatedQuiz.quiz_title}</h2>
                        <div className="flex items-center gap-2 text-sm text-slate-500">
                            <span className="px-2 py-0.5 rounded bg-slate-200 text-slate-700 text-xs font-bold uppercase">{generatedQuiz.difficulty}</span>
                            <span>•</span>
                            <span>{generatedQuiz.language}</span>
                            <span>•</span>
                            <span>{generatedQuiz.questions.length} Questions</span>
                        </div>
                    </div>
                    <div className="flex flex-col gap-2 items-end">
                        <div className="bg-white px-4 py-2 rounded-lg border border-slate-200 text-center">
                            <span className="block text-xs text-slate-400 uppercase font-bold">Access Code</span>
                            <span className="block text-xl font-mono font-bold text-indigo-600">{generatedQuiz.accessCode}</span>
                        </div>
                        <div className="flex gap-2">
                             <span className="text-xs text-slate-500 font-medium bg-slate-200 px-2 py-1 rounded">
                                  Replays: {generatedQuiz.replayLimit === 0 ? 'Unlimited' : generatedQuiz.replayLimit}
                             </span>
                             {generatedQuiz.timeLimit && generatedQuiz.timeLimit > 0 && (
                                <span className="text-xs text-slate-500 font-medium bg-slate-200 px-2 py-1 rounded">
                                    Time: {generatedQuiz.timeLimit} min
                                </span>
                             )}
                        </div>
                    </div>
                 </div>

                 <div className="space-y-4">
                    {generatedQuiz.questions.map((q, idx) => (
                        <div key={idx} className="bg-white p-4 rounded-lg border border-slate-200">
                            <div className="flex gap-3">
                                <span className="flex-shrink-0 w-6 h-6 rounded-full bg-indigo-100 text-indigo-600 flex items-center justify-center text-xs font-bold">{idx + 1}</span>
                                <div>
                                    <p className="font-medium text-slate-800">{q.prompt}</p>
                                    <p className="text-xs text-slate-400 mt-1 uppercase">{q.type}</p>
                                    <p className="text-sm text-slate-600 mt-2"><span className="font-medium text-slate-500">Answer:</span> {q.correct_answer}</p>
                                </div>
                            </div>
                        </div>
                    ))}
                 </div>
              </div>
            </div>
          )}
        </div>
      )}

      {view === 'list' && (
        <div className="grid gap-6 md:grid-cols-2 lg:grid-cols-3">
            {quizzes.length === 0 ? (
                <div className="col-span-full py-20 text-center bg-white rounded-xl border border-dashed border-slate-300">
                    <LayoutList className="w-12 h-12 text-slate-300 mx-auto mb-4" />
                    <h3 className="text-lg font-medium text-slate-900">No quizzes yet</h3>
                    <p className="text-slate-500">Create your first quiz to get started.</p>
                </div>
            ) : (
                quizzes.map(quiz => {
                    const scheduled = isScheduled(quiz);
                    return (
                        <div key={quiz.id} className="bg-white p-6 rounded-xl border border-slate-200 shadow-sm hover:shadow-md transition-shadow relative">
                            <div className="flex justify-between items-start mb-4">
                                <div className="flex gap-2">
                                    <span className="px-2 py-1 bg-indigo-100 text-indigo-700 text-xs font-bold rounded uppercase">{quiz.language}</span>
                                    {scheduled ? (
                                        <span className="px-2 py-1 bg-amber-100 text-amber-700 text-xs font-bold rounded uppercase flex items-center">
                                            <Clock className="w-3 h-3 mr-1" /> Scheduled
                                        </span>
                                    ) : (
                                        <span className="px-2 py-1 bg-green-100 text-green-700 text-xs font-bold rounded uppercase flex items-center">
                                            <Check className="w-3 h-3 mr-1" /> Live
                                        </span>
                                    )}
                                </div>
                                <button onClick={() => deleteQuiz(quiz.id)} className="text-slate-400 hover:text-red-500">
                                    <Trash2 className="w-5 h-5" />
                                </button>
                            </div>
                            <h3 className="text-lg font-bold text-slate-900 mb-2 truncate">{quiz.quiz_title}</h3>
                            <p className="text-sm text-slate-500 mb-4 flex items-center">
                                <Calendar className="w-3 h-3 mr-1" />
                                {scheduled 
                                    ? `Available: ${new Date(quiz.publishedAt).toLocaleDateString()} ${new Date(quiz.publishedAt).toLocaleTimeString([], {hour: '2-digit', minute:'2-digit'})}`
                                    : `Published: ${new Date(quiz.createdDate).toLocaleDateString()}`
                                }
                            </p>

                            <div className="mb-4 p-3 bg-slate-50 rounded-lg border border-slate-200 flex items-center justify-between group">
                                <div>
                                    <span className="text-xs text-slate-400 uppercase font-bold block">Class Code</span>
                                    <span className="text-lg font-mono font-bold text-slate-800 tracking-wider">{quiz.accessCode}</span>
                                </div>
                                <button 
                                    onClick={() => copyToClipboard(quiz.accessCode, quiz.id)}
                                    className="p-2 hover:bg-white rounded-md text-slate-400 hover:text-indigo-600 transition-colors"
                                    title="Copy Code"
                                >
                                    {copiedId === quiz.id ? <Check className="w-5 h-5 text-emerald-500" /> : <Copy className="w-5 h-5" />}
                                </button>
                            </div>

                            <div className="pt-4 border-t border-slate-100 flex items-center justify-between">
                                <div className="flex items-center text-sm text-slate-500">
                                    <Users className="w-4 h-4 mr-2" />
                                    {allAttempts.filter(a => a.quizId === quiz.id).length} Attempts
                                </div>
                                <div className="flex flex-col items-end text-xs text-slate-400">
                                    <span>Replay Limit: {quiz.replayLimit === 0 || quiz.replayLimit === undefined ? '∞' : quiz.replayLimit}</span>
                                    <span>Time: {quiz.timeLimit ? `${quiz.timeLimit}m` : '∞'}</span>
                                </div>
                            </div>
                        </div>
                    );
                })
            )}
        </div>
      )}

      {view === 'reports' && (
        <div className="bg-white rounded-xl shadow-sm border border-slate-200 overflow-hidden">
            <div className="p-6 border-b border-slate-100">
                <h3 className="text-lg font-bold text-slate-900">Recent Student Attempts</h3>
            </div>
            <div className="overflow-x-auto">
                <table className="w-full text-left text-sm text-slate-600">
                    <thead className="bg-slate-50 text-slate-900 font-semibold">
                        <tr>
                            <th className="p-4">Date</th>
                            <th className="p-4">Student</th>
                            <th className="p-4">Quiz Title</th>
                            <th className="p-4">Level</th>
                            <th className="p-4">Score</th>
                        </tr>
                    </thead>
                    <tbody className="divide-y divide-slate-100">
                        {allAttempts.length === 0 ? (
                            <tr>
                                <td colSpan={5} className="p-8 text-center text-slate-400">No student attempts recorded yet.</td>
                            </tr>
                        ) : (
                            allAttempts.map(attempt => (
                                <tr key={attempt.id} className="hover:bg-slate-50">
                                    <td className="p-4">{new Date(attempt.date).toLocaleDateString()}</td>
                                    <td className="p-4 font-medium text-slate-900">{attempt.studentName}</td>
                                    <td className="p-4">
                                        <div>{attempt.quizTitle}</div>
                                        <div className="text-xs text-slate-400 mt-0.5">{attempt.language}</div>
                                    </td>
                                    <td className="p-4">
                                        <span className="px-2 py-1 bg-slate-100 rounded text-xs text-slate-600 font-medium">{attempt.difficulty || 'N/A'}</span>
                                    </td>
                                    <td className="p-4">
                                        <span className={`inline-block px-2 py-1 rounded text-xs font-bold ${
                                            (attempt.score / attempt.totalQuestions) >= 0.8 ? 'bg-green-100 text-green-700' :
                                            (attempt.score / attempt.totalQuestions) >= 0.5 ? 'bg-yellow-100 text-yellow-700' : 'bg-red-100 text-red-700'
                                        }`}>
                                            {Math.round((attempt.score / attempt.totalQuestions) * 100)}%
                                        </span>
                                    </td>
                                </tr>
                            ))
                        )}
                    </tbody>
                </table>
            </div>
        </div>
      )}
    </div>
  );
};

export default TeacherDashboard;

import React, { useState, useEffect } from 'react';
import { QuizData, QuizAttempt, UserResponse } from '../types';
import { storageService } from '../services/storageService';
import { generateFeedback } from '../services/geminiService';
import QuizDisplay from './QuizDisplay';
import ResultsView from './ResultsView';
import HistoryChart from './HistoryChart';
import { PlayCircle, Award, User, Search, KeyRound } from 'lucide-react';

const StudentDashboard: React.FC = () => {
  const [view, setView] = useState<'join' | 'quiz' | 'results'>('join');
  const [studentName, setStudentName] = useState(''); // Confirmed name (logged in)
  const [nameInput, setNameInput] = useState(''); // Form input state
  const [joinCode, setJoinCode] = useState('');
  const [activeQuiz, setActiveQuiz] = useState<QuizData | null>(null);
  const [userResponses, setUserResponses] = useState<UserResponse[]>([]);
  const [myAttempts, setMyAttempts] = useState<QuizAttempt[]>([]);
  const [isLoadingFeedback, setIsLoadingFeedback] = useState(false);
  const [joinError, setJoinError] = useState('');

  useEffect(() => {
    // Check for saved name
    const savedName = localStorage.getItem('linguaListen_studentName');
    if (savedName) {
        setStudentName(savedName);
        setNameInput(savedName);
    }
  }, []);

  useEffect(() => {
    if (studentName) {
        setMyAttempts(storageService.getStudentAttempts(studentName));
    }
  }, [studentName]);

  const handleNameSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (nameInput.trim()) {
        const cleanName = nameInput.trim();
        localStorage.setItem('linguaListen_studentName', cleanName);
        setStudentName(cleanName);
        setMyAttempts(storageService.getStudentAttempts(cleanName));
    }
  };

  const handleSignOut = () => {
    localStorage.removeItem('linguaListen_studentName'); 
    setStudentName('');
    setNameInput('');
  };

  const handleJoinQuiz = (e: React.FormEvent) => {
    e.preventDefault();
    setJoinError('');

    if (joinCode.length !== 6) {
        setJoinError('Please enter a valid 6-digit code.');
        return;
    }

    const allQuizzes = storageService.getQuizzes();
    const quiz = allQuizzes.find(q => q.accessCode === joinCode);

    if (quiz) {
        const now = new Date();
        const publishDate = new Date(quiz.publishedAt);

        if (now < publishDate) {
            setJoinError(`This quiz is scheduled to open on ${publishDate.toLocaleDateString()} at ${publishDate.toLocaleTimeString([], {hour: '2-digit', minute:'2-digit'})}`);
            return;
        }

        setActiveQuiz(quiz);
        setView('quiz');
        setJoinCode('');
    } else {
        setJoinError('Quiz not found. Please check the code.');
    }
  };

  const handleQuizSubmit = async (answers: Record<string, string>) => {
    if (!activeQuiz) return;

    setView('results');
    setIsLoadingFeedback(true);

    const responses: UserResponse[] = [];
    let correctCount = 0;

    for (const q of activeQuiz.questions) {
      const userAnswer = answers[q.id] || '';
      const isCorrect = userAnswer.toLowerCase().trim() === q.correct_answer.toLowerCase().trim();
      if (isCorrect) correctCount++;
      responses.push({ questionId: q.id, userAnswer, isCorrect });
    }

    setUserResponses(responses);

    // Save attempt
    const newAttempt: QuizAttempt = {
      id: Date.now().toString(),
      date: new Date().toISOString(),
      quizId: activeQuiz.id,
      quizTitle: activeQuiz.quiz_title,
      studentName: studentName,
      score: correctCount,
      totalQuestions: activeQuiz.questions.length,
      language: activeQuiz.language,
      difficulty: activeQuiz.difficulty
    };

    storageService.saveAttempt(newAttempt);
    setMyAttempts(prev => [newAttempt, ...prev]);

    // Async Feedback
    const feedbackPromises = responses.map(async (response) => {
       const question = activeQuiz.questions.find(q => q.id === response.questionId);
       if (!question) return response;

       if (!response.isCorrect || question.type === 'Short Answer') {
          const feedback = await generateFeedback(question, response.userAnswer, activeQuiz.language);
          return { ...response, feedback };
       }
       return response;
    });

    try {
        const responsesWithFeedback = await Promise.all(feedbackPromises);
        setUserResponses(responsesWithFeedback);
    } catch (e) {
        console.error("Error fetching feedback", e);
    } finally {
        setIsLoadingFeedback(false);
    }
  };

  if (!studentName) {
    return (
        <div className="min-h-[60vh] flex flex-col items-center justify-center max-w-md mx-auto px-4">
            <div className="bg-white p-8 rounded-2xl shadow-lg border border-slate-100 w-full text-center">
                <div className="w-16 h-16 bg-indigo-100 rounded-full flex items-center justify-center mx-auto mb-6">
                    <User className="w-8 h-8 text-indigo-600" />
                </div>
                <h2 className="text-2xl font-bold text-slate-900 mb-2">Student Profile</h2>
                <p className="text-slate-500 mb-6">Enter your name to track your progress and take quizzes.</p>
                <form onSubmit={handleNameSubmit} className="space-y-4">
                    <input 
                        type="text" 
                        value={nameInput}
                        onChange={(e) => setNameInput(e.target.value)}
                        placeholder="Your Name (e.g. Ali, Sarah)"
                        className="w-full px-4 py-3 border border-slate-300 rounded-lg focus:ring-2 focus:ring-indigo-500 focus:border-indigo-500 outline-none transition-all"
                        required
                    />
                    <button type="submit" className="w-full py-3 bg-indigo-600 text-white rounded-lg font-semibold hover:bg-indigo-700 transition-colors">
                        Continue
                    </button>
                </form>
            </div>
        </div>
    );
  }

  if (view === 'quiz' && activeQuiz) {
    return (
        <div className="animate-fade-in">
            <button 
                onClick={() => setView('join')}
                className="mb-6 text-slate-500 hover:text-indigo-600 font-medium flex items-center"
            >
                ← Back to Dashboard
            </button>
            <QuizDisplay 
                quizData={activeQuiz} 
                studentName={studentName}
                onSubmit={handleQuizSubmit} 
            />
        </div>
    );
  }

  if (view === 'results' && activeQuiz) {
    return (
        <div className="animate-fade-in">
             <ResultsView 
              quizData={activeQuiz} 
              userResponses={userResponses} 
              onRetry={() => setView('join')}
              onHome={() => setView('join')}
              isLoadingFeedback={isLoadingFeedback}
            />
        </div>
    );
  }

  return (
    <div className="max-w-6xl mx-auto space-y-8 animate-fade-in">
        <div className="flex justify-between items-center bg-white p-6 rounded-xl border border-slate-200 shadow-sm">
            <div>
                <h1 className="text-2xl font-bold text-slate-900">Welcome back, {studentName}!</h1>
                <p className="text-slate-500">You have completed {myAttempts.length} quizzes so far.</p>
            </div>
            <button onClick={handleSignOut} className="text-sm text-slate-400 hover:text-red-500">
                Sign Out
            </button>
        </div>

        <div className="grid grid-cols-1 lg:grid-cols-3 gap-8">
            <div className="lg:col-span-2">
                <div className="bg-indigo-600 rounded-2xl p-8 text-white shadow-xl shadow-indigo-200">
                    <div className="flex items-center space-x-3 mb-4">
                        <KeyRound className="w-8 h-8 text-indigo-200" />
                        <h2 className="text-2xl font-bold">Join a Quiz</h2>
                    </div>
                    <p className="text-indigo-100 mb-6">Enter the 6-digit access code provided by your teacher to start a new listening comprehension quiz.</p>

                    <form onSubmit={handleJoinQuiz} className="max-w-md">
                        <div className="relative">
                            <input 
                                type="text" 
                                value={joinCode}
                                onChange={(e) => setJoinCode(e.target.value.replace(/\D/g, '').slice(0, 6))}
                                placeholder="Enter 6-digit code"
                                className="w-full pl-4 pr-32 py-4 rounded-xl text-slate-900 placeholder-slate-400 font-bold text-lg tracking-widest focus:outline-none focus:ring-4 focus:ring-indigo-400"
                            />
                            <button 
                                type="submit"
                                className="absolute right-2 top-2 bottom-2 px-6 bg-indigo-800 hover:bg-indigo-900 text-white font-bold rounded-lg transition-colors"
                            >
                                JOIN
                            </button>
                        </div>
                        {joinError && (
                            <div className="mt-3 text-red-200 text-sm font-medium bg-red-500/20 py-1 px-3 rounded inline-block">
                                {joinError}
                            </div>
                        )}
                    </form>
                </div>
            </div>

            <div className="space-y-6">
                <h2 className="text-xl font-bold text-slate-800 flex items-center">
                    <Award className="w-5 h-5 mr-2 text-amber-500" />
                    Your Progress
                </h2>
                <HistoryChart attempts={myAttempts} />

                <div className="bg-white rounded-xl border border-slate-200 shadow-sm overflow-hidden">
                    <div className="p-4 bg-slate-50 font-medium text-sm text-slate-700 border-b border-slate-200">Recent Activity</div>
                    <div className="divide-y divide-slate-100 max-h-64 overflow-y-auto">
                        {myAttempts.map(attempt => (
                            <div key={attempt.id} className="p-4 hover:bg-slate-50">
                                <p className="font-medium text-sm text-slate-900 truncate">{attempt.quizTitle}</p>
                                <div className="flex justify-between mt-1 text-xs text-slate-500">
                                    <span>{new Date(attempt.date).toLocaleDateString()}</span>
                                    <span className={attempt.score/attempt.totalQuestions >= 0.5 ? 'text-emerald-600' : 'text-red-500'}>
                                        {attempt.score}/{attempt.totalQuestions}
                                    </span>
                                </div>
                            </div>
                        ))}
                        {myAttempts.length === 0 && (
                            <div className="p-4 text-sm text-slate-400 text-center">No history yet.</div>
                        )}
                    </div>
                </div>
            </div>
        </div>
    </div>
  );
};

export default StudentDashboard;

