import { fileToGenerativePart } from './geminiService';
import { Question } from "../types/types";

// ... other imports

export const extractTextFromDocument = async (file: File): Promise<string> => {
  const model = 'gemini-flash-latest';
  const docPart = await fileToGenerativePart(file);
  const prompt = "Extract all readable text from this document. Return only the raw text content without formatting or markdown.";

  try {
    const result = await genAI.getGenerativeModel({ model: model }).generateContent([prompt, docPart]);
    const response = await result.response;
    const text = response.text();
    return text || "";
  } catch (error) {
    console.error('Error extracting text from document:', error);
