  const [currentQPrompt, setCurrentQPrompt] = useState('');
  const [currentQAnswer, setCurrentQAnswer] = useState('');
  const [currentQOptions, setCurrentQOptions] = useState<string[]>(['', '', '', '']); // 4 empty options

  const [copiedId, setCopiedId] = useState<string | null>(null);

  useEffect(() => {
    loadData();
  }, []);

  const loadData = () => {
    setQuizzes(storageService.getQuizzes());
    setAllAttempts(storageService.getAttempts());
  };

  // --- AI Handlers ---

  const handleAIFileSelect = async (file: File) => {
    setLoading(true);
    setLoadingMessage(`Processing media for ${difficulty} level...`);

    const steps = ['Uploading media...', 'Transcribing audio...', 'Analyzing language...', 'Creating questions...'];
    let stepIdx = 0;
    const interval = setInterval(() => {
        if(stepIdx < steps.length) {
            setLoadingMessage(steps[stepIdx]);
            stepIdx++;
        }
    }, 2000);

    try {
      const quiz = await generateQuizFromMedia(file, difficulty, replayLimit, questionCount, timeLimit);
      clearInterval(interval);
      setGeneratedQuiz(quiz);
      setPublishMode('now');
      setScheduleDate('');
    } catch (error) {
      clearInterval(interval);
      console.error(error);
      alert('Error generating quiz. Please try again. Note: Large files may exceed browser storage limits.');
    } finally {
      setLoading(false);
    }
  };

  // --- Manual Handlers ---

  const handleManualAddQuestion = () => {
      if (!currentQPrompt || !currentQAnswer) {
          alert("Please provide a question prompt and the correct answer.");
          return;
      }

      const newQ: Question = {
          id: crypto.randomUUID(),
          type: currentQType,
          prompt: currentQPrompt,
          correct_answer: currentQAnswer,
          options: (currentQType === 'Multiple Choice') ? currentQOptions.filter(o => o.trim() !== '') : undefined
      };

      setManualQuestions([...manualQuestions, newQ]);
      // Reset current input
      setCurrentQPrompt('');
      setCurrentQAnswer('');
      setCurrentQOptions(['', '', '', '']);
  };

  const handleManualDeleteQuestion = (id: string) => {
      setManualQuestions(manualQuestions.filter(q => q.id !== id));
  };

  const handleScanDocument = async () => {
    if (!docFile) {
      alert("Please upload a document first.");
      return;
    }

    setLoading(true);
    setLoadingMessage("Scanning document for questions...");

    try {
      const extractedQuestions = await extractQuestionsFromDocument(docFile);
      setManualQuestions(prev => [...prev, ...extractedQuestions]);
      setDocFile(null); // Clear file after processing
      alert(`Successfully imported ${extractedQuestions.length} questions!`);
